const hasMeaningfulPreviousPolicyData = (policy) => {
    if (!policy || typeof policy !== 'object') {
        return false;
    }

    const fieldsToCheck = [
        'PolicyNumber',
        'PolicyFrom',
        'PolicyTo',
        'PolicyIssuedDate',
        'CompanyName',
        'SumInsured',
        'PremiumAmount',
        'NoClaimBonus',
        'RenewDate',
        'PdfFile',
        'PdfFileName',
        'ClaimStatementPDFfile',
        'ClaimStatementPDFfileName',
        'PreviousPolicyNumber',
        'NomineeName',
        'NomineeRelation',
        'NomineeDob',
        'NomineeAge',
        'AddOnCover',
        'ClaimExpireInPolicy',
        'PreviousAgentName',
        'PreviousAgentCode',
        'PreviousAgentContactNumber'
    ];

    return fieldsToCheck.some((field) => {
        const value = policy[field];

        if (value === null || value === undefined) {
            return false;
        }

        if (typeof value === 'string') {
            return value.trim() !== '';
        }

        if (typeof value === 'number') {
            return !isNaN(value);
        }

        if (typeof value === 'boolean') {
            return true;
        }

        return !!value;
    });
};

// Helper function to create notifications
const createNotification = async (notificationData) => {
    try {
        const notification = await db.notification.create({
            title: notificationData.title,
            message: notificationData.message,
            type: notificationData.type, // 'vehicle', 'mediclaim', 'loan', 'builder', 'system'
            category: notificationData.category, // 'user_added', 'user_updated', etc.
            user_id: notificationData.user_id || null,
            target_user_id: notificationData.target_user_id || null,
            record_id: notificationData.record_id || null,
            is_important: notificationData.is_important || false,
            metadata: notificationData.metadata || null
        });
        console.log('🔔 [NOTIFICATION] Created:', notification.title);
        return notification;
    } catch (error) {
        console.error('❌ [NOTIFICATION] Error creating notification:', error);
        return null;
    }
};
