// Original controllers directory, so __dirname-relative upload/download paths
// keep resolving to Backend/uploads exactly as before the split.
const CTRL_DIR = path.join(__dirname, "../../../app/controllers");

/**
 * Universal de-dup helper: ensure a consumer→category mapping exists, creating
 * it only if missing. Use this EVERYWHERE a consumer is assigned to a vertical
 * (consumer/vehicle/loan/mediclaim/life pages) so the same person+category can
 * never get a duplicate mapping, regardless of which path created them.
 */
async function ensureCategoryMapping(user_consumer_id, category_id, user_role_id) {
  if (!user_consumer_id || !category_id) return null;
  const [row] = await consumerRoleMapping.findOrCreate({
    where: { user_consumer_id, category_id },
    defaults: { user_consumer_id, category_id, user_role_id: user_role_id || null },
  });
  return row;
}

/**
 * Universal file-upload helper. Saves one express-fileupload file object to the
 * shared uploads dir and returns the stored filename. Use this EVERYWHERE a file
 * is uploaded (consumer docs, vehicle RC, life docs, blog images…) instead of
 * re-implementing mv()/writeFile per controller.
 */
/**
 * Save an uploaded file into a per-module subfolder under /uploads and return
 * the stored path RELATIVE to /uploads (e.g. "vehicle/<uuid>-rc.pdf"), so files
 * are organised by area (consumer-kyc, vehicle, …). The download URL is
 * BASE_URL/uploads/<that path>.
 */
async function saveUpload(fileObj, subdir = "misc") {
  if (!fileObj) return null;
  const safeSub = String(subdir).replace(/[^a-z0-9/_-]/gi, "") || "misc";
  const dir = path.join(CTRL_DIR, "../../uploads", safeSub);
  await fsExtra.ensureDir(dir);
  const uniqueName = `${uuidv4()}-${path.basename(fileObj.name)}`;
  const uploadPath = path.join(dir, uniqueName);
  if (fileObj.mv) {
    await fileObj.mv(uploadPath);
  } else if (fileObj.data) {
    await fsExtra.writeFile(uploadPath, fileObj.data);
  } else {
    throw new Error("saveUpload: no valid file handling method (mv/data) on file object");
  }
  return `${safeSub}/${uniqueName}`;
}

const ConsumerDocument = db.consumerDocument;

/**
 * Store/replace a consumer-level document (KYC). One row per (user_id,
 * categoryId): re-uploading the same type replaces the file. Used so KYC docs
 * live on the consumer and are reused across verticals instead of re-asked per
 * policy.
 */
async function upsertConsumerDocument(user_id, categoryId, file) {
  if (!user_id || !categoryId || !file) return null;
  const existing = await ConsumerDocument.findOne({ where: { user_id, categoryId } });
  if (existing) {
    existing.file = file;
    await existing.save();
    return existing;
  }
  return ConsumerDocument.create({ user_id, categoryId, file });
}

